{
  "clusters": [
    {
      "id": "review-changes-button-icon-swap",
      "rationale": "ReviewChangesButton.tsx directly modified: SweepIcon replaced with CloseIcon, so all ReviewChangesButton stories are directly affected by the visual change.",
      "representative": "manager-sidebar-reviewchangesbutton--idle",
      "signature": { "type": "prefix", "value": "manager-sidebar-reviewchangesbutton--" }
    },
    {
      "id": "manager-main-resolver-log-level",
      "rationale": "manager-main stories are transitively affected via the ResolverFactory.ts change (logger.warn demoted to logger.debug), pulling in the shared dependency graph through their import chain.",
      "representative": "manager-main--default",
      "signature": { "type": "prefix", "value": "manager-main--" }
    },
    {
      "id": "sidebar-refs-transitive",
      "rationale": "Refs stories are transitively affected by the ResolverFactory.ts log-level change propagating through the shared change-detection dependency graph imported by sidebar components.",
      "representative": "manager-sidebar-refs--optimized",
      "signature": { "type": "prefix", "value": "manager-sidebar-refs--" }
    },
    {
      "id": "sidebar-filter-panel-transitive",
      "rationale": "FilterPanel and Filter stories are transitively affected by the ResolverFactory.ts change via the shared sidebar/change-detection import graph.",
      "representative": "manager-sidebar-filterpanel--basic",
      "signature": { "type": "regex", "value": "^manager-sidebar-filter(panel)?--" }
    },
    {
      "id": "sidebar-tree-node-transitive",
      "rationale": "Tree and TreeNode stories are transitively affected by the ResolverFactory.ts change through shared sidebar imports.",
      "representative": "manager-sidebar-tree--full",
      "signature": { "type": "regex", "value": "^manager-sidebar-tree(node)?--" }
    },
    {
      "id": "sidebar-remaining-transitive",
      "rationale": "Catch-all for all remaining manager-sidebar stories (explorer, searchresults, search, sidebar) transitively affected by the ResolverFactory.ts log-level-only change.",
      "representative": "manager-sidebar-sidebar--simple",
      "signature": { "type": "regex", "value": ".*" }
    }
  ]
}

{
  "clusters": [
    {
      "id": "ai-optin-checklist-settings",
      "rationale": "Settings pages and ChecklistWidget stories directly render the aiOptIn/aiSetupRun state that was changed: hasAiInitOptIn now defaults to true and aiOptIn is written unconditionally in initializeChecklist.",
      "representative": "manager-settings-guidepage--ai-cta-open",
      "signature": { "type": "regex", "value": "^manager-settings-|^manager-components-sidebar-checklistwidget--" }
    },
    {
      "id": "sidebar-main-stories",
      "rationale": "Top-level Sidebar and Filter stories import checklist.ts directly and will reflect the changed aiOptIn default and unconditional setState behaviour.",
      "representative": "manager-sidebar-sidebar--simple",
      "signature": { "type": "regex", "value": "^manager-sidebar-sidebar--|^manager-sidebar-filter--|^manager-sidebar-menu--" }
    },
    {
      "id": "testing-widget-container-menu",
      "rationale": "TestingWidget and container Menu stories are also direct importers of checklist.ts and may surface the updated aiOptIn store state.",
      "representative": "manager-sidebar-testingwidget--default",
      "signature": { "type": "regex", "value": "^manager-sidebar-testingwidget--|^manager-container-menu--" }
    },
    {
      "id": "sidebar-refs-search-filterpanel-tree",
      "rationale": "Refs, Search, SearchResults, FilterPanel, TreeNode, Tree, and SidebarBottom stories are transitively affected through the shared checklist store whose aiOptIn semantics changed.",
      "representative": "manager-sidebar-refs--optimized",
      "signature": { "type": "regex", "value": "^manager-sidebar-(refs|search|searchresults|filterpanel|treenode|tree|explorer|sidebarbottom)--" }
    },
    {
      "id": "manager-main",
      "rationale": "manager-main stories are transitively affected via the same checklist store import graph; catch-all for the main layout stories.",
      "representative": "manager-main--default",
      "signature": { "type": "prefix", "value": "manager-main--" }
    },
    {
      "id": "remaining",
      "rationale": "Catch-all bucket for any flagged stories not matched by a more specific signature above.",
      "representative": "manager-sidebar-sidebar--loading",
      "signature": { "type": "regex", "value": ".*" }
    }
  ]
}

{
  "clusters": [
    {
      "id": "sidebar-refs-index-update",
      "rationale": "These stories directly render the Refs component and are most likely to expose regressions in the new explicit setRef/setIndex calls added to onAllStatusChange.",
      "representative": "manager-sidebar-refs--with-source-code",
      "signature": { "type": "prefix", "value": "manager-sidebar-refs--" }
    },
    {
      "id": "sidebar-status-filter",
      "rationale": "These stories exercise status filtering, the filter panel, the review-changes button, and the tree's change-detection views — all of which depend on recomputeStatusFilter and the subsequent setIndex re-application changed in the diff.",
      "representative": "manager-sidebar-filterpanel--with-statuses",
      "signature": { "type": "regex", "value": "^manager-sidebar-(filterpanel|filter|reviewchangesbutton|tree)--" }
    },
    {
      "id": "manager-sidebar-general",
      "rationale": "Remaining sidebar stories (sidebar composite, search, menu, heading, testing widget, explorer, tree nodes, file-search, notifications) transitively import stories.ts and may surface timing/state regressions from the async flow change.",
      "representative": "manager-sidebar-sidebar--with-refs",
      "signature": { "type": "regex", "value": "^manager-(sidebar|notifications)-" }
    },
    {
      "id": "manager-shell",
      "rationale": "Manager shell stories (main, layout, mobile, iframe, panel, settings, components, container, upgradeblock, error boundary) import the manager-api module and will re-render under the changed status-change lifecycle.",
      "representative": "manager-main--default",
      "signature": { "type": "regex", "value": "^manager-" }
    },
    {
      "id": "addons-and-components-transitive",
      "rationale": "Catch-all for all addon and shared-component stories that are transitively affected via the manager-api import graph but are not manager UI stories themselves.",
      "representative": "addons-vitest-testproviderrender--default",
      "signature": { "type": "regex", "value": ".*" }
    }
  ]
}

{
  "clusters": [
    {
      "id": "manager-sidebar-filter-aware",
      "rationale": "Stories for sidebar filter/filterpanel components directly exercise the tag and status filter APIs (resetTagFilters, setAllTagFilters, addTagFilters, removeTagFilters, resetStatusFilters, etc.) whose recompute calls are now properly awaited in the diff.",
      "representative": "manager-sidebar-filterpanel--with-statuses",
      "signature": { "type": "regex", "value": "^manager-sidebar-(filter|filterpanel|reviewchangesbutton)--" }
    },
    {
      "id": "manager-sidebar-core",
      "rationale": "Sidebar refs, sidebar, search, tree, menu, and related manager UI stories all import through manager-api/modules/stories.ts and are directly affected by the async recomputeTagsFilter/recomputeStatusFilter fix.",
      "representative": "manager-sidebar-sidebar--statuses-collapsed",
      "signature": { "type": "regex", "value": "^manager-(sidebar|mobile|main|layout|upgradeblock|settings|iframe|panel|container)--?" }
    },
    {
      "id": "manager-components",
      "rationale": "Manager component stories (preview, checklistwidget, textflip, tourguide, particles, etc.) transitively import manager-api and are affected by the async filter recompute change.",
      "representative": "manager-components-preview-viewport--default",
      "signature": { "type": "prefix", "value": "manager-components-" }
    },
    {
      "id": "addons-and-component-testing",
      "rationale": "Addon and component-testing stories (accessibility, vitest, interactions, actions, docs) all transitively import manager-api/modules/stories.ts through the manager context, pulling in the awaited recompute change.",
      "representative": "addons-vitest-testproviderrender--default",
      "signature": { "type": "regex", "value": "^(addons|actions|component-testing|controls|highlight)--?" }
    },
    {
      "id": "remaining",
      "rationale": "Catch-all for any remaining flagged stories (shared UI components, overlay, select, tabs, button, etc.) that transitively depend on manager-api but don't fit the more specific manager or addons clusters.",
      "representative": "components-bar-bar--default",
      "signature": { "type": "regex", "value": ".*" }
    }
  ]
}
